// MainActivity.kt
package com.example.shareintenthandler

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.widget.ImageView
import android.widget.TextView
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity

class MainActivity : AppCompatActivity() {

    private lateinit var tvSharedText: TextView
    private lateinit var ivSharedImage: ImageView
    private lateinit var tvStatus: TextView

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        tvSharedText = findViewById(R.id.tvSharedText)
        ivSharedImage = findViewById(R.id.ivSharedImage)
        tvStatus = findViewById(R.id.tvStatus)

        handleIntent(intent)
    }

    override fun onNewIntent(intent: Intent?) {
        super.onNewIntent(intent)
        intent?.let { handleIntent(it) }
    }

    private fun handleIntent(intent: Intent) {
        when (intent.action) {
            Intent.ACTION_SEND -> {
                if (intent.type?.startsWith("text/") == true) {
                    handleSharedText(intent)
                } else if (intent.type?.startsWith("image/") == true) {
                    handleSharedImage(intent)
                }
            }
            Intent.ACTION_SEND_MULTIPLE -> {
                if (intent.type?.startsWith("image/") == true) {
                    handleMultipleImages(intent)
                }
            }
        }
    }

    private fun handleSharedText(intent: Intent) {
        intent.getStringExtra(Intent.EXTRA_TEXT)?.let { sharedText ->
            tvStatus.text = "Shared Text/URL Received"
            tvSharedText.text = sharedText
            ivSharedImage.setImageDrawable(null)
            
            if (isUrl(sharedText)) {
                processUrl(sharedText)
            } else {
                processText(sharedText)
            }
        }
    }

    private fun handleSharedImage(intent: Intent) {
        (intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM))?.let { imageUri ->
            tvStatus.text = "Shared Image Received"
            tvSharedText.text = "Image URI: $imageUri"
            ivSharedImage.setImageURI(imageUri)
            processImage(imageUri)
        }
    }

    private fun handleMultipleImages(intent: Intent) {
        intent.getParcelableArrayListExtra<Uri>(Intent.EXTRA_STREAM)?.let { imageUris ->
            tvStatus.text = "Multiple Images Received (${imageUris.size})"
            tvSharedText.text = "Received ${imageUris.size} images"
            
            if (imageUris.isNotEmpty()) {
                ivSharedImage.setImageURI(imageUris[0])
            }
            
            processMultipleImages(imageUris)
        }
    }

    private fun isUrl(text: String): Boolean {
        return text.startsWith("http://") || text.startsWith("https://")
    }

    private fun processUrl(url: String) {
        Toast.makeText(this, "Processing URL: $url", Toast.LENGTH_SHORT).show()
    }

    private fun processText(text: String) {
        Toast.makeText(this, "Processing text: ${text.take(50)}...", Toast.LENGTH_SHORT).show()
    }

    private fun processImage(imageUri: Uri) {
        Toast.makeText(this, "Processing image: $imageUri", Toast.LENGTH_SHORT).show()
    }

    private fun processMultipleImages(imageUris: List<Uri>) {
        Toast.makeText(this, "Processing ${imageUris.size} images", Toast.LENGTH_SHORT).show()
    }
}